import React from "react";
import Navbar from 'react-bootstrap/Navbar';
import Nav from 'react-bootstrap/Nav';
import { withRouter } from 'react-router-dom';
import "../styles/header.css";
import "../index.css";

const linkToText = {
  "/aboutMe" : "ABOUT",
  "/reviews" : "REVIEWS", 
  "/portfolio" : "PORTFOLIO", 
  "/contact" : "CONTACT"
};

class Header extends React.Component {

  getLink = (linkName) => {

    return (
      <Nav.Link
        className="header-text"
        href={linkName}
        key={linkName}
      >
        { linkToText[linkName] }
      </Nav.Link>
    );
  }

  render() {
    return (
      <div >

      <Navbar bg="light" expand="md" fixed="top" onSelect="test()">
        <Navbar.Brand href="/">
            <img
                src={require("../images/AR.png")}
                width="50"
                height="45"
            />
        </Navbar.Brand>

        <Navbar.Toggle aria-controls="responsive-navbar-nav" />
        <Navbar.Collapse id="responsive-navbar-nav">
          <Nav className="ml-auto">
            <Nav.Link href="/aboutMe" passHref>ABOUT</Nav.Link>
            <Nav.Link href="/reviews" passHref>Projects</Nav.Link>
            <Nav.Link href="/portfolio" passHref>Students</Nav.Link>
            <Nav.Link href="/contact" passHref>Nonprofits</Nav.Link>
          </Nav>
        </Navbar.Collapse>
      </Navbar>

        <Navbar id="site-header" className="header-outer">
            <Navbar.Brand href="/">
            <img
                src={require("../images/AR.png")}
                width="50"
                height="45"
            />
            </Navbar.Brand>
          <Nav>
            <div className="header-content">{ Object.keys(linkToText).map(this.getLink) }</div>
          </Nav>
      </Navbar>
      </div>
    );
  }
}
export default withRouter(Header);
